// Shared URL-state helper for list views (artifacts, etc.).
// Reads/writes the well-known query params (q, mediaType, groupBy, sort,
// staleness, phase, prefix, filters.*) while preserving any unrelated keys,
// including ?back=.

export type GroupBy = 'folder' | 'prefix' | 'mediaType' | 'workflowStage';

// Reserved facet URL keys (TD-029 facet contract):
//   q          — full-text search query (single)
//   mediaType  — media-type filter (single, supports X/* wildcard)
//   staleness  — staleness filter (single)
//   phase      — HELIX phase filter (single)
//   prefix     — id-prefix filter (multi: comma-separated)
//   sort       — sort key (single)
// groupBy is a Story-5 categorization axis (not a filter) and travels in
// the same URL but does NOT narrow results.
const KNOWN_KEYS = new Set(['q', 'mediaType', 'groupBy', 'sort', 'staleness', 'phase', 'prefix']);
const FILTER_PREFIX = 'filter.';

export interface ListURLState {
	q: string;
	mediaType: string | null;
	groupBy: GroupBy;
	sort: string | null;
	staleness: string | null;
	phase: string | null;
	prefix: string[];
	filters: Record<string, string>;
}

export const DEFAULT_GROUP_BY: GroupBy = 'folder';

function parseGroupBy(raw: string | null): GroupBy {
	if (raw === 'prefix' || raw === 'mediaType' || raw === 'folder' || raw === 'workflowStage')
		return raw;
	return DEFAULT_GROUP_BY;
}

export function readState(params: URLSearchParams): ListURLState {
	const filters: Record<string, string> = {};
	for (const [k, v] of params.entries()) {
		if (k.startsWith(FILTER_PREFIX)) filters[k.slice(FILTER_PREFIX.length)] = v;
	}
	const rawPrefix = params.get('prefix');
	const prefix = rawPrefix
		? rawPrefix
				.split(',')
				.map((s) => s.trim())
				.filter((s) => s.length > 0)
		: [];
	return {
		q: params.get('q') ?? '',
		mediaType: params.get('mediaType'),
		groupBy: parseGroupBy(params.get('groupBy')),
		sort: params.get('sort'),
		staleness: params.get('staleness'),
		phase: params.get('phase'),
		prefix,
		filters
	};
}

// writeState mutates a copy of `params` with the patch applied. Unrelated
// keys (including `back`) are preserved. Empty/null values delete the key.
export function writeState(params: URLSearchParams, patch: Partial<ListURLState>): URLSearchParams {
	const next = new URLSearchParams(params);

	if ('q' in patch) {
		if (patch.q) next.set('q', patch.q);
		else next.delete('q');
