    10	// Canvas backgrounds the graph paints onto. Mirrored from tailwind.config.js
    11	// semanticColors — if those move, update both sides.
    12	const tokens = {
    13		'bg-canvas': '#F4EFE6',
    14		'dark-bg-canvas': '#1A1815',
