    19	function srgbChannel(c: number): number {
    20		const v = c / 255;
    21		return v <= 0.03928 ? v / 12.92 : Math.pow((v + 0.055) / 1.055, 2.4);
    22	}
    23	
    24	function relLuminance(hex: string): number {
    25		const m = hex.replace('#', '');
    26		const r = parseInt(m.slice(0, 2), 16);
    27		const g = parseInt(m.slice(2, 4), 16);
    28		const b = parseInt(m.slice(4, 6), 16);
    29		return 0.2126 * srgbChannel(r) + 0.7152 * srgbChannel(g) + 0.0722 * srgbChannel(b);
    30	}
    31	
    32	function contrast(a: string, b: string): number {
    33		const la = relLuminance(a);
    34		const lb = relLuminance(b);
    35		const [hi, lo] = la > lb ? [la, lb] : [lb, la];
    36		return (hi + 0.05) / (lo + 0.05);
    37	}
    38	
    39	function readVar(scope: 'light' | 'dark', name: string): string {
    40		// CSS is split into a light block (":root, :root.light, .light") and a dark
    41		// block (":root.dark, .dark"). Grab the body for the requested scope and
    42		// pull the variable definition out of it.
    43		const blockRe =
    44			scope === 'dark'
    45				? /:root\.dark,\s*\n?\s*\.dark\s*\{([\s\S]*?)\}/
    46				: /:root,\s*\n?\s*:root\.light,\s*\n?\s*\.light\s*\{([\s\S]*?)\}/;
    47		const block = blockRe.exec(cssSource);
    48		if (!block) throw new Error(`could not locate ${scope} block in app.css`);
    49		const m = new RegExp(`--${name}\\s*:\\s*(#[0-9A-Fa-f]{6})`).exec(block[1]);
    50		if (!m) throw new Error(`--${name} not found in ${scope} block`);
    51		return m[1];
    52	}
