    54	describe('D3Graph edge ink', () => {
    55		it('uses fg-muted tokens for edge stroke and arrowhead fill (not border-line)', () => {
    56			// Tailwind v4 only generates text-* utilities for these custom tokens, so
    57			// the edge/arrow drive their stroke and fill from currentColor instead of
    58			// stroke-*/fill-* utilities. The text-fg-muted class still anchors the
    59			// canonical color choice.
    60			expect(graphSource).toContain("'text-fg-muted dark:text-dark-fg-muted'");
    61			expect(graphSource).toMatch(/\.attr\(\s*'stroke'\s*,\s*'currentColor'\s*\)/);
    62			expect(graphSource).toMatch(/\.attr\(\s*'fill'\s*,\s*'currentColor'\s*\)/);
    63			expect(graphSource).not.toMatch(/stroke-border-line|fill-border-line/);
    64			// Subtlety must be carried by color, not alpha — no stroke-opacity attr.
    65			expect(graphSource).not.toMatch(/stroke-opacity/);
    66		});
